let om = null;
function am() {
  if (!om && typeof document == "object" && document.body) {
    let { style: n } = document.body,
      e = [],
      t = new Set();
    for (let r in n)
      r != "cssText" &&
        r != "cssFloat" &&
        typeof n[r] == "string" &&
        (/[A-Z]/.test(r) &&
          (r = r.replace(/[A-Z]/g, (i) => "-" + i.toLowerCase())),
          t.has(r) || (e.push(r), t.add(r)));
    om = e.sort().map((r) => ({ type: "property", label: r, apply: r + ": " }));
  }
  return om || [];
}
